  "changes": [
    {
      "category": "ip_assignment",
      "summary": "IP ownership shifted from exclusive Provider ownership to Customer retention of all rights except limited Provider use of feedback.",
      "original_text": "All right, title, and interest in and to any feedback, suggestions, ideas, comments, improvements, modifications, or other information of any kind provided by Customer to Provider, and any derivative works thereof, shall be owned exclusively by Provider. Customer hereby irrevocably assigns to Provider all such rights without further compensation.",
